#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a, b, c, d;
        scanf("%d %d %d %d", &a, &b, &c, &d);
        long long count = 0;
        for (int x = a; x <= b; x++) {
            for (int y = c; y <= d; y++) {
                if (x < y) count++;
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

