code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            int c = sc.nextInt();
            int d = sc.nextInt();
            long count = 0;
            for (int x = a; x <= b; x++) {
                for (int y = c; y <= d; y++) {
                    if (x < y) count++;
                }
            }
            System.out.println(count);
        }
    }
}

